        leftSearch.style.padding = "6px 10px";
        leftSearch.style.background = "#222";
        leftSearch.style.color = "#fff";
        leftSearch.style.border = "none";
        leftSearch.style.borderBottom = "1px solid #333";
        leftSearch.style.boxSizing = "border-box";
