    var _selectOptionMapCache = {};
    var _selectOptionMapLengths = {};

    function buildOrGetSelectOptionMap(selectEl) {
        log("ImportIE: buildOrGetSelectOptionMap start");
        if (!selectEl || !selectEl.id) {
            log("ImportIE: buildOrGetSelectOptionMap no select or no id, building fresh map");
            var freshMap = {};
            var fOpts = selectEl ? selectEl.querySelectorAll("option") : [];
            var fi = 0;
            while (fi < fOpts.length) {
                var fVal = (fOpts[fi].value + "").trim();
                if (fVal.length > 0) {
                    freshMap[fVal] = fOpts[fi];
                }
                fi = fi + 1;
            }
            log("ImportIE: buildOrGetSelectOptionMap fresh map size=" + String(Object.keys(freshMap).length));
            return freshMap;
        }
        var cacheKey = selectEl.id;
        var currentOpts = selectEl.querySelectorAll("option");
        var currentLen = currentOpts.length;
        if (_selectOptionMapCache.hasOwnProperty(cacheKey) && _selectOptionMapLengths[cacheKey] === currentLen) {
            log("ImportIE: buildOrGetSelectOptionMap returning cached map for id=" + cacheKey + " size=" + String(Object.keys(_selectOptionMapCache[cacheKey]).length));
            return _selectOptionMapCache[cacheKey];
        }
        var newMap = {};
        var ni = 0;
        while (ni < currentOpts.length) {
            var nVal = (currentOpts[ni].value + "").trim();
            if (nVal.length > 0) {
                newMap[nVal] = currentOpts[ni];
            }
            ni = ni + 1;
        }
        _selectOptionMapCache[cacheKey] = newMap;
        _selectOptionMapLengths[cacheKey] = currentLen;
        log("ImportIE: buildOrGetSelectOptionMap built new map for id=" + cacheKey + " size=" + String(Object.keys(newMap).length));
        return newMap;
    }

    function isCurrentSelectValue(selectEl, targetValue) {
        log("ImportIE: isCurrentSelectValue target=" + String(targetValue));
        if (!selectEl) {
            return false;
        }
        var current = (selectEl.value + "").trim();
        var target = (targetValue + "").trim();
        var result = current === target;
        log("ImportIE: isCurrentSelectValue current=" + current + " target=" + target + " match=" + String(result));
        return result;
    }

    async function select2SelectByValue(containerOrSelect, value) {
        log("ImportIE: select2SelectByValue value='" + String(value) + "'");
        var sel = null;
        if (containerOrSelect && containerOrSelect.tagName && containerOrSelect.tagName.toLowerCase() === "select") {
            sel = containerOrSelect;
        } else if (typeof containerOrSelect === "string") {
            sel = document.querySelector(containerOrSelect);
        } else {
            var under = containerOrSelect.querySelector("select");
            if (under) {
                sel = under;
            }
        }
        if (!sel) {
            log("ImportIE: select2SelectByValue select element not found");
            return false;
        }
        sel.value = String(value);
        select2TriggerChange(sel);
        await sleep(importIERandomDelay());
        var after = (sel.value + "").trim();
        if (after === String(value).trim()) {
            log("ImportIE: select2SelectByValue confirmed value='" + String(after) + "'");
            return true;
        }
        log("ImportIE: select2SelectByValue value mismatch expected='" + String(value) + "' got='" + String(after) + "'");
        sel.value = String(value);
        select2TriggerChange(sel);
        await sleep(300);
        after = (sel.value + "").trim();
        log("ImportIE: select2SelectByValue retry result='" + String(after) + "'");
        return after === String(value).trim();
    }

    async function select2SelectByText(containerOrSelect, text) {
        log("ImportIE: select2SelectByText text='" + String(text) + "'");
        var sel = null;
        if (containerOrSelect && containerOrSelect.tagName && containerOrSelect.tagName.toLowerCase() === "select") {
            sel = containerOrSelect;
        } else if (typeof containerOrSelect === "string") {
            sel = document.querySelector(containerOrSelect);
        } else {
            var under = containerOrSelect.querySelector("select");
            if (under) {
                sel = under;
            }
        }
        if (!sel) {
            log("ImportIE: select2SelectByText select element not found");
            return false;
        }
        var opts = sel.querySelectorAll("option");
        var normalTarget = normalizeTextForCompare(text);
        var oi = 0;
        while (oi < opts.length) {
            var oTxt = normalizeTextForCompare((opts[oi].textContent + ""));
            if (oTxt === normalTarget) {
                sel.value = opts[oi].value;
                select2TriggerChange(sel);
                await sleep(importIERandomDelay());
                log("ImportIE: select2SelectByText matched exact text index=" + String(oi));
                return true;
            }
            oi = oi + 1;
        }
        log("ImportIE: select2SelectByText no exact match for text='" + String(text) + "'");
        return false;
    }

    function normalizeTextForCompare(t) {
        var s = (t + "").trim();
        s = s.replace(/\s+/g, " ");
        s = s.toLowerCase();
        return s;
    }

    function extractIECode(text) {
        var s = (text + "").trim();
        var match = IE_CODE_REGEX.exec(s);
        if (match) {
            var prefix = match[1].toUpperCase();
            var num = match[2];
            var suffix = (match[3] || "").toLowerCase();
            var code = prefix + num + suffix;
            return code;
        }
        return "";
    }

    function extractIECodeStrict(text) {
        var s = (text + "").trim();
        var re = /\b(INC|EXC)(\d+)([a-zA-Z]?)\b/i;
        var match = re.exec(s);
        if (match) {
            var prefix = match[1].toUpperCase();
            var num = match[2];
            var suffix = (match[3] || "").toLowerCase();
            return prefix + num + suffix;
        }
        var re2 = /\b(INC|EXC)\s+(\d+)([a-zA-Z]?)\b/i;
        var match2 = re2.exec(s);
        if (match2) {
            var prefix2 = match2[1].toUpperCase();
            var num2 = match2[2];
            var suffix2 = (match2[3] || "").toLowerCase();
            return prefix2 + num2 + suffix2;
        }
        return "";
    }

    function isValidEligibilityPage() {
        log("ImportIE: isValidEligibilityPage checking");
        var hostname = location.hostname;
        var path = location.pathname;
        var validHost = false;
        var hi = 0;
        while (hi < ELIGIBILITY_VALID_HOSTNAMES.length) {
            if (hostname === ELIGIBILITY_VALID_HOSTNAMES[hi]) {
                validHost = true;
                break;
            }
            hi = hi + 1;
        }
        if (!validHost) {
            log("ImportIE: invalid hostname='" + String(hostname) + "'");
            return false;
        }
        if (path !== ELIGIBILITY_LIST_PATH) {
            log("ImportIE: invalid path='" + String(path) + "'");
            return false;
        }
        log("ImportIE: valid eligibility page");
        return true;
    }

