    // Choose an epoch (prefer screening) and route to its show page for autoepoch.
    async function processStudyShowRouting() {
        var tbody = await waitForSelector('tbody#epochTableBody', 5000);
        if (!tbody) {
            return;
        }
        var anchors = tbody.querySelectorAll('a[href^="/secure/administration/studies/epoch/show/"]');
        if (anchors.length === 0) {
            return;
        }

        var screeningEntry = null;
        var otherEntries = [];
        var i = 0;
        while (i < anchors.length) {
            var a = anchors[i];
            var name = (a.textContent + "").trim();
            var href = a.getAttribute("href") + "";
            if (isScreeningLabel(name) && !screeningEntry) {
                screeningEntry = { name: name, href: href};
            } else {
                otherEntries.push({name: name, href: href})
            }
            i = i + 1;
        }
        var epochQueue = [];
        if (screeningEntry) {
            epochQueue.push(screeningEntry);
        }
        var k = 0;
        while (k < otherEntries.length) {
            epochQueue.push(otherEntries[k]);
            k = k + 1;
        }
        if (epochQueue.length === 0) return;

        setEpochQueue(epochQueue);
        setEpochIndex(0);
        setLinkedSourceCounter(0);
        clearUsedActivityPlans();

        var mode = getRunMode();
        if (mode === "all") {
            updateRunAllPopupStatus("Running Add Cohort Subjects (1/" + String(epochQueue.length) + ")");
        }
        var firstHref = epochQueue[0].href;
        location.href = location.origin + firstHref + "?autoepoch=1";
        log("Routing to epoch show: " + epochQueue[0].name);
    }

    // If edit-study flag present, set study to ACTIVE and save reason.
    async function processStudyEditBasicsPageIfFlag() {
        var flag = null;
        try {
            flag = localStorage.getItem(STORAGE_EDIT_STUDY);
        } catch (e) {}
        if (!flag) {
            return;
        }
        try {
            localStorage.removeItem(STORAGE_EDIT_STUDY);
            log("Cleared study edit flag");
        } catch (e2) {}
        var selectEl = await waitForSelector('select#studyState', 5000);
        if (!selectEl) {
            return;
        }
        var current = selectEl.value + "";
        var mode = getRunMode();
        var alreadyActive = current === "ACTIVE";
        if (alreadyActive) {
            var cancelBtn = document.querySelector('button.btn.default[onclick*="/secure/administration/studies/show"]');
            if (cancelBtn) {
                if (mode === "all") {
                    setContinueEpoch();
                } else {
                    try {
                        localStorage.setItem(STORAGE_CHECK_ELIG_LOCK, "1");
                    } catch (e4) {}
                }
                cancelBtn.click();
                log("Study already ACTIVE; returning to show");
            }
            return;
        }
        var need = current !== "ACTIVE";
        if (need) {
            selectEl.value = "ACTIVE";
            var evt = new Event("change", { bubbles: true });
            selectEl.dispatchEvent(evt);
            log("Study state set to ACTIVE");
        }
        var reasonEl = await waitForSelector('textarea#reasonForChange', 5000);
        if (!reasonEl) {
            return;
        }
        reasonEl.value = "Status update";
        var inputEvt = new Event("input", { bubbles: true });
        reasonEl.dispatchEvent(inputEvt);
        var saveBtn = await waitForSelector('button.btn.green[type="submit"]', 5000);
        if (!saveBtn) {
            return;
        }
        if (mode === "all") {
            setContinueEpoch();
        } else {
            try {
                localStorage.setItem(STORAGE_CHECK_ELIG_LOCK, "1");
            } catch (e6) {}
        }
        saveBtn.click();
        log("Study basics saved");
    }

    // Route from epoch to cohort show when running epoch/all flows.
    async function processEpochShowPage() {
        var auto = getQueryParam("autoepoch");
        var mode = getRunMode();
        var go = (mode === "epoch" || mode === "all") || (auto === "1" && mode && mode.length > 0);
        if (!go) {
            return;
        }

        var anchors = document.querySelectorAll('a[href^="/secure/administration/studies/cohort/show/"]');
        if (anchors.length === 0) {
            log("No cohorts found on epoch page; skipping to next epoch");
            var eq = getEpochQueue();
            var ei = getEpochIndex();
            if (eq.length > 0 && ei < eq.length) {
                markEpochCompleted(eq[ei].href);
            }
            advanceToNextEpoch();
            return;
        }
        var target = anchors[0];
        var href = target.getAttribute("href") + "";

        if (href.length === 0) {
            return;
        }

        var epochQueue = getEpochQueue();
        var epochIdx = getEpochIndex();
        var isScreening = false;
        if (epochQueue.length > 0 && epochIdx < epochQueue.length) {
            var currentEpoch = epochQueue[epochIdx];
            isScreening = isScreeningLabel(currentEpoch.name);
        }
        else {
            isScreening = true;
        }

        if (isScreening) {
            location.href = location.origin + href + "?autocohort=1";
            log("Routing to cohort show (screening)")
        }
        else {
            location.href = location.origin + href + "?autocohortnonscreen=1";
            log("Routing to cohort show (non-screening)")
        }
    }

